import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Google Drive चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/google-drive.md","filePath":"hi/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"hi/upload/google-drive.md"};function c(p,e,h,g,u,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="google-drive-चैनल-जोड़ना" tabindex="-1">Google Drive चैनल जोड़ना <a class="header-anchor" href="#google-drive-चैनल-जोड़ना" aria-label="Permalink to &quot;Google Drive चैनल जोड़ना&quot;">​</a></h1><h2 id="पहले-क्या-चाहिए" tabindex="-1">पहले क्या चाहिए <a class="header-anchor" href="#पहले-क्या-चाहिए" aria-label="Permalink to &quot;पहले क्या चाहिए&quot;">​</a></h2><p>शुरू करने से पहले ये items तैयार रखें:</p><table tabindex="0"><thead><tr><th>ज़रूरत</th><th>क्यों चाहिए</th></tr></thead><tbody><tr><td>Google account</td><td>Google Cloud access और Google Drive authorize करने के लिए</td></tr><tr><td>Google Cloud project</td><td>Drive API enable और OAuth credentials create करने के लिए</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed को <code>Client ID</code>, <code>Client Secret</code> और <code>Refresh Token</code> पाने के लिए</td></tr><tr><td>आपका ImgBed domain</td><td>OAuth redirect URI के लिए। यह आपके actual used domain से match होना चाहिए।</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-google-drive-api-enable-करें" tabindex="-1">Step 1: Google Drive API enable करें <a class="header-anchor" href="#step-1-google-drive-api-enable-करें" aria-label="Permalink to &quot;Step 1: Google Drive API enable करें&quot;">​</a></h3><ol><li>Google Cloud Console खोलें।</li><li>नया project बनाएँ या existing project चुनें।</li><li><code>APIs &amp; Services</code> पर जाएँ।</li><li><code>Enable APIs and Services</code> पर क्लिक करें।</li><li><code>Google Drive API</code> search करें।</li><li>इसे खोलकर enable करें।</li></ol><h3 id="step-2-oauth-consent-screen-configure-करें" tabindex="-1">Step 2: OAuth Consent Screen configure करें <a class="header-anchor" href="#step-2-oauth-consent-screen-configure-करें" aria-label="Permalink to &quot;Step 2: OAuth Consent Screen configure करें&quot;">​</a></h3><ol><li>Google Cloud में <code>Google Auth Platform</code> खोलें।</li><li>app name, support email और developer contact email जैसी basic <code>Branding</code> information पूरी करें।</li><li><code>Audience</code> खोलें।</li><li>अधिकतर self-hosted personal deployments के लिए <code>External</code> चुनें।</li><li>अगर <code>External</code> चुनते हैं, तो authorize करना वाला Google account <code>Test users</code> में जोड़ें।</li><li><code>Data Access</code> खोलें।</li><li>required Google Drive permissions जोड़ें।</li></ol><h3 id="step-3-oauth-2-0-client-बनाएँ" tabindex="-1">Step 3: OAuth 2.0 Client बनाएँ <a class="header-anchor" href="#step-3-oauth-2-0-client-बनाएँ" aria-label="Permalink to &quot;Step 3: OAuth 2.0 Client बनाएँ&quot;">​</a></h3><ol><li><code>Google Auth Platform</code> में <code>Clients</code> खोलें।</li><li>नया client बनाएँ।</li><li>application type को <code>Web application</code> करें।</li><li>client को पहचानने लायक नाम दें।</li><li>authorized JavaScript origins में अपना ImgBed URL डालें, जैसे:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>authorized redirect URIs में डालें:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="OAuth client बनाएँ" loading="lazy"></p><p><img src="'+a+'" alt="Domain और callback URL डालें" loading="lazy"></p><p>client बन जाने के बाद ये values copy करें:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-google-drive-channel-भरें" tabindex="-1">Step 4: Google Drive channel भरें <a class="header-anchor" href="#step-4-google-drive-channel-भरें" aria-label="Permalink to &quot;Step 4: Google Drive channel भरें&quot;">​</a></h2><p>Upload Settings में <code>Google Drive</code> चुनें और भरें:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>क्या डालें</th></tr></thead><tbody><tr><td>Channel name</td><td>पहचानने लायक नाम, जैसे <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Google Cloud से Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud से Client Secret</td></tr><tr><td>Refresh Token</td><td>अभी खाली छोड़ें। अगले step में लें।</td></tr><tr><td>Root directory</td><td>optional। default <code>imgbed</code>।</td></tr></tbody></table><p><img src="'+o+'" alt="Client details ImgBed में paste करें" loading="lazy"></p><h2 id="step-5-refresh-token-लें" tabindex="-1">Step 5: Refresh Token लें <a class="header-anchor" href="#step-5-refresh-token-लें" aria-label="Permalink to &quot;Step 5: Refresh Token लें&quot;">​</a></h2><ol><li><code>Get Token</code> पर क्लिक करें।</li><li>जिस Google account को connect करना है उसे चुनें।</li><li>authorization prompts complete करें।</li><li>callback page <code>Refresh Token</code> दिखाएगा।</li><li>इसे copy करें।</li><li>ImgBed में लौटकर <code>Refresh Token</code> field में paste करें।</li></ol><p><img src="'+l+`" alt="Authorization के बाद Refresh Token copy करें" loading="lazy"></p><p>अगर बाद में Google account बदलते हैं, OAuth client बदलते हैं, या पुरानी authorization expire हो जाती है, तो channel delete करने की ज़रूरत नहीं। edit page खोलें और <code>Reauthorize</code> पर क्लिक करें।</p><h2 id="step-6-channel-save-करें" tabindex="-1">Step 6: Channel save करें <a class="header-anchor" href="#step-6-channel-save-करें" aria-label="Permalink to &quot;Step 6: Channel save करें&quot;">​</a></h2><p>सभी fields भरने के बाद channel save करें।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud खोलें</span></span>
<span class="line"><span>-&gt; project बनाएँ या चुनें</span></span>
<span class="line"><span>-&gt; Google Drive API enable करें</span></span>
<span class="line"><span>-&gt; Google Auth Platform configure करें</span></span>
<span class="line"><span>-&gt; Audience External हो तो अपना Google account Test users में जोड़ें</span></span>
<span class="line"><span>-&gt; Web application OAuth client बनाएँ</span></span>
<span class="line"><span>-&gt; redirect URI के रूप में https://your-domain.com/api/oauth/google/callback use करें</span></span>
<span class="line"><span>-&gt; ImgBed में Client ID और Client Secret भरें</span></span>
<span class="line"><span>-&gt; Get Token क्लिक करें</span></span>
<span class="line"><span>-&gt; Google से sign in और authorize करें</span></span>
<span class="line"><span>-&gt; callback page से Refresh Token copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में paste करके save करें</span></span>
<span class="line"><span>-&gt; test image upload करें</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const k=i(d,[["render",c]]);export{f as __pageData,k as default};
